1	/**
2	 * Per-tool grammar — spec §16.4 / §16.5.
3	 *
4	 * Each tool's interaction model is captured here as plain data so the
5	 * tool can be unit-tested without DOM. The shape is consistent across
6	 * tools so the canvas can switch on `kind` and dispatch input.
7	 */
8	
9	export type { WallLocationLine } from '@bim-ai/core';
10	import type { WallLocationLine } from '@bim-ai/core';
11	
12	/* ────────────────────────────────────────────────────────────────────── */
13	/* EDT-06 — Tool grammar polish (Chain / Multiple / Tag-on-Place /        */
14	/*           Numeric input). The canvas wires the per-tool reducers in    */
15	/*           this file plus a top-level `ToolGrammarModifiers` block      */
16	/*           that feeds the Options Bar.                                  */
17	/* ────────────────────────────────────────────────────────────────────── */
18	
19	/** Modifiers that the canvas Options Bar exposes to the user. */
20	export interface ToolGrammarModifiers {
21	  /** Place Wall continues from the last endpoint until Esc / different tool. */
22	  chainable: boolean;
23	  /** Insert Door / Window stays in tool until Esc; otherwise exits after first placement. */
24	  multipleable: boolean;
25	  /** During wall / door / window placement, auto-place a tag of the configured family. */
26	  tagOnPlace: { enabled: boolean; tagFamilyId?: string };
27	  /** Numeric input mode: typing a digit while drawing pops a numeric input field. */
28	  numericInputActive: boolean;
29	}
30	
31	export function defaultToolGrammarModifiers(): ToolGrammarModifiers {
32	  return {
33	    chainable: true,
34	    multipleable: false,
35	    tagOnPlace: { enabled: false },
36	    numericInputActive: false,
37	  };
38	}
39	
40	/** A tool's static capability set — drives which Options Bar toggles appear. */
41	export interface ToolCapabilities {
42	  chainable: boolean;
43	  multipleable: boolean;
44	  tagOnPlace: boolean;
45	  /** Whether the tool supports typing a numeric distance while drawing. */
46	  numericInput: boolean;
47	}
48	
49	export const TOOL_CAPABILITIES: Record<string, ToolCapabilities> = {
50	  wall: { chainable: true, multipleable: false, tagOnPlace: true, numericInput: true },
51	  door: { chainable: false, multipleable: true, tagOnPlace: true, numericInput: false },
52	  window: { chainable: false, multipleable: true, tagOnPlace: true, numericInput: false },
53	  beam: { chainable: false, multipleable: false, tagOnPlace: false, numericInput: true },
54	  column: { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
55	  ceiling: { chainable: false, multipleable: false, tagOnPlace: false, numericInput: false },
56	  shaft: { chainable: false, multipleable: false, tagOnPlace: false, numericInput: false },
57	  align: { chainable: false, multipleable: false, tagOnPlace: false, numericInput: false },
58	  split: { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
59	  trim: { chainable: false, multipleable: true, tagOnPlace: false, numericInput: false },
60	  'wall-join': { chainable: false, multipleable: false, tagOnPlace: false, numericInput: false },
61	  'wall-opening': {
62	    chainable: false,
63	    multipleable: false,
64	    tagOnPlace: false,
65	    numericInput: false,
66	  },
67	};
