69	/**
70	 * Numeric-input field state — appears at the cursor while a numeric-capable
71	 * tool is mid-draw and the user types a digit. `axis` toggles on Tab so a
72	 * second number can drive the perpendicular direction.
73	 */
74	export interface NumericInputState {
75	  active: boolean;
76	  value: string;
77	  axis: 'primary' | 'perpendicular';
78	}
79	
80	export function initialNumericInputState(): NumericInputState {
81	  return { active: false, value: '', axis: 'primary' };
82	}
83	
84	export type NumericInputEvent =
85	  | { kind: 'start'; firstDigit: string }
86	  | { kind: 'append'; digit: string }
87	  | { kind: 'backspace' }
88	  | { kind: 'tab-axis' }
89	  | { kind: 'commit' }
90	  | { kind: 'cancel' };
91	
92	export function reduceNumericInput(
93	  state: NumericInputState,
94	  event: NumericInputEvent,
95	): NumericInputState {
96	  switch (event.kind) {
97	    case 'start':
98	      return { active: true, value: event.firstDigit, axis: 'primary' };
99	    case 'append':
100	      if (!state.active) return state;
101	      return { ...state, value: state.value + event.digit };
102	    case 'backspace':
103	      if (!state.active) return state;
104	      return { ...state, value: state.value.slice(0, -1) };
105	    case 'tab-axis':
106	      if (!state.active) return state;
107	      return {
108	        ...state,
109	        axis: state.axis === 'primary' ? 'perpendicular' : 'primary',
110	      };
111	    case 'commit':
112	    case 'cancel':
113	      return initialNumericInputState();
114	  }
115	}
116	
117	export type ToolGrammarKind =
118	  | 'wall'
119	  | 'door'
120	  | 'window'
121	  | 'floor'
122	  | 'roof'
123	  | 'stair'
124	  | 'railing'
125	  | 'room'
126	  | 'dimension'
127	  | 'section'
128	  | 'tag'
129	  | 'align'
130	  | 'split'
131	  | 'trim'
132	  | 'wall-join';
