134	export const WALL_LOCATION_LINE_ORDER: WallLocationLine[] = [
135	  'wall-centerline',
136	  'finish-face-exterior',
137	  'finish-face-interior',
138	  'core-centerline',
139	  'core-face-exterior',
140	  'core-face-interior',
141	];
142	
143	/** Cycle through the §16.4.1 location-line set on `Tab`. */
144	export function cycleWallLocationLine(current: WallLocationLine): WallLocationLine {
145	  const idx = WALL_LOCATION_LINE_ORDER.indexOf(current);
146	  if (idx < 0) return WALL_LOCATION_LINE_ORDER[0]!;
147	  return WALL_LOCATION_LINE_ORDER[(idx + 1) % WALL_LOCATION_LINE_ORDER.length]!;
148	}
149	
150	/** Wall tool state machine — minimum necessary to drive a chain mode
151	 * without leaking pointer details into the controller. */
152	export interface WallChainState {
153	  active: boolean;
154	  startMm: { xMm: number; yMm: number } | null;
155	  /** Locked endpoint after a click; chain mode begins from here. */
156	  chainAnchorMm: { xMm: number; yMm: number } | null;
157	  locationLine: WallLocationLine;
158	}
159	
160	export function initialWallChainState(): WallChainState {
161	  return {
162	    active: false,
163	    startMm: null,
164	    chainAnchorMm: null,
165	    locationLine: 'wall-centerline',
166	  };
167	}
168	
169	export type WallChainEvent =
170	  | { kind: 'tool-activated' }
171	  | { kind: 'tool-deactivated' }
172	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
173	  | { kind: 'cancel' }
174	  | { kind: 'tab-cycle-location' }
175	  | { kind: 'enter-finish' };
176	
177	export interface WallChainEffect {
178	  /** Wall span to commit, when a 2nd click closes a segment. */
179	  commitSegment?: {
180	    startMm: { xMm: number; yMm: number };
181	    endMm: { xMm: number; yMm: number };
182	    locationLine: WallLocationLine;
183	  };
184	  /** True when the tool stays active after the event. */
185	  stillActive: boolean;
186	  /** True when this event broke the chain (Esc). */
187	  chainBroken?: boolean;
188	}
189	
190	export function reduceWallChain(
191	  state: WallChainState,
192	  event: WallChainEvent,
193	): { state: WallChainState; effect: WallChainEffect } {
194	  if (event.kind === 'tool-activated') {
195	    return {
196	      state: { ...state, active: true, startMm: null, chainAnchorMm: null },
197	      effect: { stillActive: true },
198	    };
199	  }
200	  if (event.kind === 'tool-deactivated') {
201	    return {
202	      state: { ...initialWallChainState() },
203	      effect: { stillActive: false },
204	    };
205	  }
206	  if (!state.active) {
207	    return { state, effect: { stillActive: false } };
208	  }
209	  if (event.kind === 'tab-cycle-location') {
210	    return {
211	      state: { ...state, locationLine: cycleWallLocationLine(state.locationLine) },
212	      effect: { stillActive: true },
213	    };
214	  }
215	  if (event.kind === 'cancel') {
216	    return {
217	      state: { ...state, startMm: null, chainAnchorMm: null },
218	      effect: { stillActive: true, chainBroken: true },
219	    };
220	  }
221	  if (event.kind === 'enter-finish') {
222	    return {
223	      state: { ...initialWallChainState() },
224	      effect: { stillActive: false },
225	    };
226	  }
227	  // click
228	  const start = state.chainAnchorMm ?? state.startMm;
229	  if (!start) {
230	    return {
231	      state: { ...state, startMm: event.pointMm, chainAnchorMm: null },
232	      effect: { stillActive: true },
233	    };
234	  }
235	  const segment = {
236	    startMm: start,
237	    endMm: event.pointMm,
238	    locationLine: state.locationLine,
239	  };
240	  return {
241	    state: { ...state, startMm: null, chainAnchorMm: event.pointMm },
242	    effect: { commitSegment: segment, stillActive: true },
243	  };
244	}
