320	/* Roof — §16.4.5                                                           */
321	/* ────────────────────────────────────────────────────────────────────── */
322	
323	export type RoofType = 'gable' | 'hip' | 'flat' | 'shed';
324	
325	export interface RoofState {
326	  type: RoofType;
327	  slopeDeg: number;
328	  /** Per-edge slope override; key is edge index. */
329	  edgeSlopes: Record<number, boolean>;
330	  eaveOverhangMm: number;
331	}
332	
333	export function initialRoofState(): RoofState {
334	  return {
335	    type: 'gable',
336	    slopeDeg: 35,
337	    edgeSlopes: {},
338	    eaveOverhangMm: 600,
339	  };
340	}
341	
342	export function toggleEdgeSlope(state: RoofState, edgeIdx: number): RoofState {
343	  const next = { ...state.edgeSlopes };
344	  next[edgeIdx] = !state.edgeSlopes[edgeIdx];
345	  return { ...state, edgeSlopes: next };
346	}
