348	/* ────────────────────────────────────────────────────────────────────── */
349	/* Stair — §16.4.6                                                          */
350	/* ────────────────────────────────────────────────────────────────────── */
351	
352	export type StairType = 'straight' | 'l-shape' | 'u-shape' | 'spiral';
353	
354	export interface StairCalcInput {
355	  baseLevelElevMm: number;
356	  topLevelElevMm: number;
357	  preferredRiserMm?: number;
358	  preferredTreadMm?: number;
359	}
360	
361	export interface StairCalcOutput {
362	  riserMm: number;
363	  treadMm: number;
364	  riserCount: number;
365	  treadCount: number;
366	  totalRiseMm: number;
367	}
368	
369	export const STAIR_RISER_MM_DEFAULT = 175;
370	export const STAIR_TREAD_MM_DEFAULT = 280;
371	
372	/** Auto-compute risers/treads for a straight run between two levels. */
373	export function computeStairRun(input: StairCalcInput): StairCalcOutput {
374	  const totalRise = input.topLevelElevMm - input.baseLevelElevMm;
375	  if (totalRise <= 0) {
376	    return {
377	      riserMm: STAIR_RISER_MM_DEFAULT,
378	      treadMm: STAIR_TREAD_MM_DEFAULT,
379	      riserCount: 0,
380	      treadCount: 0,
381	      totalRiseMm: 0,
382	    };
383	  }
384	  const desired = input.preferredRiserMm ?? STAIR_RISER_MM_DEFAULT;
385	  const riserCount = Math.max(2, Math.round(totalRise / desired));
386	  const riserMm = totalRise / riserCount;
387	  const treadMm = input.preferredTreadMm ?? STAIR_TREAD_MM_DEFAULT;
388	  return {
389	    riserMm,
390	    treadMm,
391	    riserCount,
392	    treadCount: riserCount - 1,
393	    totalRiseMm: totalRise,
394	  };
395	}
