418	/* ────────────────────────────────────────────────────────────────────── */
419	/* Room marker — §16.4.8                                                    */
420	/* ────────────────────────────────────────────────────────────────────── */
421	
422	export interface RoomMarkerInput {
423	  /** Closed boundary forming the room — typically the auto-detected
424	   * polygon under the cursor. */
425	  outlineMm: { xMm: number; yMm: number }[];
426	}
427	
428	export function centroidMm(outline: { xMm: number; yMm: number }[]): { xMm: number; yMm: number } {
429	  if (outline.length === 0) return { xMm: 0, yMm: 0 };
430	  let area = 0;
431	  let cx = 0;
432	  let cy = 0;
433	  for (let i = 0; i < outline.length; i++) {
434	    const a = outline[i]!;
435	    const b = outline[(i + 1) % outline.length]!;
436	    const cross = a.xMm * b.yMm - b.xMm * a.yMm;
437	    area += cross;
438	    cx += (a.xMm + b.xMm) * cross;
439	    cy += (a.yMm + b.yMm) * cross;
440	  }
441	  if (area === 0) {
442	    const sum = outline.reduce((acc, p) => ({ xMm: acc.xMm + p.xMm, yMm: acc.yMm + p.yMm }), {
443	      xMm: 0,
444	      yMm: 0,
445	    });
446	    return { xMm: sum.xMm / outline.length, yMm: sum.yMm / outline.length };
447	  }
448	  area /= 2;
449	  return { xMm: cx / (6 * area), yMm: cy / (6 * area) };
450	}
