513	/* ────────────────────────────────────────────────────────────────────── */
514	/* Align — §16 Modify                                                       */
515	/* ────────────────────────────────────────────────────────────────────── */
516	
517	export interface AlignState {
518	  phase: 'pick-reference' | 'pick-element';
519	  referenceMm: { xMm: number; yMm: number } | null;
520	}
521	
522	export type AlignEvent =
523	  | { kind: 'activate' }
524	  | { kind: 'deactivate' }
525	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
526	  | { kind: 'cancel' };
527	
528	export interface AlignEffect {
529	  commitAlign?: {
530	    referenceMm: { xMm: number; yMm: number };
531	    targetMm: { xMm: number; yMm: number };
532	  };
533	  stillActive: boolean;
534	}
535	
536	export function initialAlignState(): AlignState {
537	  return { phase: 'pick-reference', referenceMm: null };
538	}
539	
540	export function reduceAlign(
541	  state: AlignState,
542	  event: AlignEvent,
543	): { state: AlignState; effect: AlignEffect } {
544	  if (event.kind === 'activate') {
545	    return { state: { phase: 'pick-reference', referenceMm: null }, effect: { stillActive: true } };
546	  }
547	  if (event.kind === 'deactivate') {
548	    return {
549	      state: { phase: 'pick-reference', referenceMm: null },
550	      effect: { stillActive: false },
551	    };
552	  }
553	  if (event.kind === 'cancel') {
554	    return { state: { phase: 'pick-reference', referenceMm: null }, effect: { stillActive: true } };
555	  }
556	  // click
557	  if (state.phase === 'pick-reference') {
558	    return {
559	      state: { phase: 'pick-element', referenceMm: event.pointMm },
560	      effect: { stillActive: true },
561	    };
562	  }
563	  // pick-element + click → commit and return to pick-reference for next pair
564	  return {
565	    state: { phase: 'pick-reference', referenceMm: null },
566	    effect: {
567	      commitAlign: { referenceMm: state.referenceMm!, targetMm: event.pointMm },
568	      stillActive: true,
569	    },
570	  };
571	}
572	
573	/* ────────────────────────────────────────────────────────────────────── */
574	/* Split — §16 Modify                                                       */
575	/* ────────────────────────────────────────────────────────────────────── */
576	
577	export interface SplitState {
578	  active: boolean;
579	}
580	
581	export type SplitEvent =
582	  | { kind: 'activate' }
583	  | { kind: 'deactivate' }
584	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
585	  | { kind: 'cancel' };
586	
587	export interface SplitEffect {
588	  commitSplit?: { pointMm: { xMm: number; yMm: number } };
589	  stillActive: boolean;
590	}
591	
592	export function initialSplitState(): SplitState {
593	  return { active: false };
594	}
595	
596	export function reduceSplit(
597	  state: SplitState,
598	  event: SplitEvent,
599	): { state: SplitState; effect: SplitEffect } {
600	  if (event.kind === 'activate') {
601	    return { state: { active: true }, effect: { stillActive: true } };
602	  }
603	  if (event.kind === 'deactivate') {
604	    return { state: { active: false }, effect: { stillActive: false } };
605	  }
606	  if (event.kind === 'cancel') {
607	    return { state, effect: { stillActive: true } };
608	  }
609	  if (!state.active) {
610	    return { state, effect: { stillActive: false } };
611	  }
612	  // click while active → emit split, stay active (Revit stays in Split mode)
613	  return {
614	    state,
615	    effect: { commitSplit: { pointMm: event.pointMm }, stillActive: true },
616	  };
617	}
