641	  return { phase: 'pick-reference', referenceId: null };
642	}
643	
644	export function reduceTrim(
645	  state: TrimState,
646	  event: TrimEvent,
647	): { state: TrimState; effect: TrimEffect } {
648	  if (event.kind === 'activate') {
649	    return {
650	      state: { phase: 'pick-reference', referenceId: null },
651	      effect: { stillActive: true },
652	    };
653	  }
654	  if (event.kind === 'deactivate') {
655	    return {
656	      state: { phase: 'pick-reference', referenceId: null },
657	      effect: { stillActive: false },
658	    };
659	  }
660	  if (event.kind === 'cancel') {
661	    return {
662	      state: { phase: 'pick-reference', referenceId: null },
663	      effect: { stillActive: true },
664	    };
665	  }
666	  if (event.kind === 'click-reference') {
667	    return {
668	      state: { phase: 'pick-target', referenceId: event.elementId },
669	      effect: { stillActive: true },
670	    };
671	  }
672	  // click-target
673	  if (state.phase !== 'pick-target' || !state.referenceId) {
674	    return { state, effect: { stillActive: true } };
675	  }
676	  return {
677	    state: { phase: 'pick-reference', referenceId: null },
678	    effect: {
679	      commitTrim: {
680	        referenceId: state.referenceId,
681	        targetId: event.elementId,
682	        endHint: event.endHint,
683	      },
684	      stillActive: true,
685	    },
686	  };
687	}
688	
689	/* ────────────────────────────────────────────────────────────────────── */
690	/* Wall Join — §16 Modify                                                   */
691	/* ────────────────────────────────────────────────────────────────────── */
692	
693	export type WallJoinVariant = 'miter' | 'butt' | 'square';
694	
695	const WALL_JOIN_VARIANTS: WallJoinVariant[] = ['miter', 'butt', 'square'];
696	
697	export interface WallJoinState {
698	  phase: 'idle' | 'selected';
699	  cornerMm: { xMm: number; yMm: number } | null;
700	  wallIds: string[];
701	  joinVariant: WallJoinVariant;
702	}
703	
704	export type WallJoinEvent =
705	  | { kind: 'activate' }
706	  | { kind: 'deactivate' }
707	  | { kind: 'click-corner'; cornerMm: { xMm: number; yMm: number }; wallIds: string[] }
708	  | { kind: 'cycle' }
709	  | { kind: 'accept' }
710	  | { kind: 'cancel' };
711	
712	export interface WallJoinEffect {
713	  commitJoin?: { wallIds: string[]; variant: WallJoinVariant };
714	  stillActive: boolean;
715	}
716	
717	export function initialWallJoinState(): WallJoinState {
718	  return { phase: 'idle', cornerMm: null, wallIds: [], joinVariant: 'miter' };
719	}
720	
721	export function reduceWallJoin(
722	  state: WallJoinState,
723	  event: WallJoinEvent,
724	): { state: WallJoinState; effect: WallJoinEffect } {
725	  if (event.kind === 'activate') {
726	    return { state: initialWallJoinState(), effect: { stillActive: true } };
727	  }
728	  if (event.kind === 'deactivate') {
729	    return { state: initialWallJoinState(), effect: { stillActive: false } };
730	  }
731	  if (event.kind === 'cancel') {
732	    return { state: initialWallJoinState(), effect: { stillActive: true } };
733	  }
734	  if (event.kind === 'click-corner') {
735	    return {
736	      state: {
737	        phase: 'selected',
738	        cornerMm: event.cornerMm,
739	        wallIds: event.wallIds,
740	        joinVariant: 'miter',
741	      },
742	      effect: { stillActive: true },
743	    };
744	  }
745	  if (event.kind === 'cycle' && state.phase === 'selected') {
746	    const idx = WALL_JOIN_VARIANTS.indexOf(state.joinVariant);
747	    const next = WALL_JOIN_VARIANTS[(idx + 1) % WALL_JOIN_VARIANTS.length]!;
748	    return { state: { ...state, joinVariant: next }, effect: { stillActive: true } };
749	  }
750	  if (event.kind === 'accept' && state.phase === 'selected') {
751	    return {
752	      state: initialWallJoinState(),
753	      effect: {
754	        commitJoin: { wallIds: state.wallIds, variant: state.joinVariant },
755	        stillActive: true,
756	      },
757	    };
758	  }
759	  return { state, effect: { stillActive: true } };
760	}
761	
762	/* ────────────────────────────────────────────────────────────────────── */
763	/* Wall Opening — §16 Openings                                            */
764	/* ────────────────────────────────────────────────────────────────────── */
765	
766	export interface WallOpeningState {
767	  phase: 'pick-wall' | 'define-rect';
768	  hostWallId: string | null;
769	  anchorMm: { xMm: number; yMm: number } | null;
770	}
771	
772	export type WallOpeningEvent =
773	  | { kind: 'activate' }
774	  | { kind: 'deactivate' }
775	  | { kind: 'click-wall'; wallId: string; pointMm: { xMm: number; yMm: number } }
776	  | { kind: 'drag-end'; cornerMm: { xMm: number; yMm: number } }
777	  | { kind: 'cancel' };
778	
779	export interface WallOpeningEffect {
780	  commitWallOpening?: {
781	    hostWallId: string;
782	    anchorMm: { xMm: number; yMm: number };
783	    cornerMm: { xMm: number; yMm: number };
784	  };
785	  stillActive: boolean;
786	}
787	
788	export function initialWallOpeningState(): WallOpeningState {
789	  return { phase: 'pick-wall', hostWallId: null, anchorMm: null };
790	}
791	
792	export function reduceWallOpening(
793	  state: WallOpeningState,
794	  event: WallOpeningEvent,
795	): { state: WallOpeningState; effect: WallOpeningEffect } {
796	  if (event.kind === 'activate') {
797	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
798	  }
799	  if (event.kind === 'deactivate') {
800	    return { state: initialWallOpeningState(), effect: { stillActive: false } };
801	  }
802	  if (event.kind === 'cancel') {
803	    return { state: initialWallOpeningState(), effect: { stillActive: true } };
804	  }
805	  if (event.kind === 'click-wall' && state.phase === 'pick-wall') {
806	    return {
807	      state: { phase: 'define-rect', hostWallId: event.wallId, anchorMm: event.pointMm },
808	      effect: { stillActive: true },
809	    };
810	  }
811	  if (
812	    event.kind === 'drag-end' &&
813	    state.phase === 'define-rect' &&
814	    state.hostWallId &&
815	    state.anchorMm
816	  ) {
817	    return {
818	      state: initialWallOpeningState(),
819	      effect: {
820	        commitWallOpening: {
821	          hostWallId: state.hostWallId,
822	          anchorMm: state.anchorMm,
823	          cornerMm: event.cornerMm,
824	        },
825	        stillActive: true,
826	      },
827	    };
828	  }
829	  return { state, effect: { stillActive: true } };
830	}
831	
832	/* ────────────────────────────────────────────────────────────────────── */
833	/* Shaft — §16 Openings                                                   */
834	/* ────────────────────────────────────────────────────────────────────── */
835	
836	export interface ShaftState {
837	  phase: 'idle' | 'sketch';
838	  verticesMm: Array<{ xMm: number; yMm: number }>;
839	}
840	
841	export type ShaftEvent =
842	  | { kind: 'activate' }
843	  | { kind: 'deactivate' }
844	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
845	  | { kind: 'close-loop' }
846	  | { kind: 'cancel' };
847	
848	export interface ShaftEffect {
849	  commitShaft?: { verticesMm: Array<{ xMm: number; yMm: number }> };
850	  stillActive: boolean;
851	}
852	
853	export function initialShaftState(): ShaftState {
854	  return { phase: 'idle', verticesMm: [] };
855	}
856	
857	export function reduceShaft(
858	  state: ShaftState,
859	  event: ShaftEvent,
860	): { state: ShaftState; effect: ShaftEffect } {
861	  if (event.kind === 'activate') {
862	    return { state: initialShaftState(), effect: { stillActive: true } };
863	  }
864	  if (event.kind === 'deactivate') {
865	    return { state: initialShaftState(), effect: { stillActive: false } };
866	  }
867	  if (event.kind === 'cancel') {
868	    return { state: initialShaftState(), effect: { stillActive: true } };
869	  }
870	  if (event.kind === 'click') {
871	    return {
872	      state: { phase: 'sketch', verticesMm: [...state.verticesMm, event.pointMm] },
873	      effect: { stillActive: true },
874	    };
875	  }
876	  if (event.kind === 'close-loop' && state.verticesMm.length >= 3) {
877	    return {
878	      state: initialShaftState(),
879	      effect: { commitShaft: { verticesMm: state.verticesMm }, stillActive: true },
880	    };
881	  }
882	  return { state, effect: { stillActive: true } };
883	}
884	
885	/* ────────────────────────────────────────────────────────────────────── */
886	/* C16 Column — single-click placement                                      */
887	/* ────────────────────────────────────────────────────────────────────── */
888	
889	export type ColumnState = { phase: 'idle' };
890	
891	export type ColumnEvent =
892	  | { kind: 'activate' }
893	  | { kind: 'deactivate' }
894	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
895	  | { kind: 'cancel' };
896	
897	export interface ColumnEffect {
898	  commitColumn?: { positionMm: { xMm: number; yMm: number } };
899	  stillActive: boolean;
900	}
901	
902	export function initialColumnState(): ColumnState {
903	  return { phase: 'idle' };
904	}
905	
906	export function reduceColumn(
907	  state: ColumnState,
908	  event: ColumnEvent,
909	): { state: ColumnState; effect: ColumnEffect } {
910	  if (event.kind === 'deactivate') {
911	    return { state: initialColumnState(), effect: { stillActive: false } };
912	  }
913	  if (event.kind === 'activate' || event.kind === 'cancel') {
914	    return { state: initialColumnState(), effect: { stillActive: event.kind === 'activate' } };
915	  }
916	  if (event.kind === 'click') {
917	    return {
918	      state: initialColumnState(),
919	      effect: { commitColumn: { positionMm: event.pointMm }, stillActive: true },
920	    };
921	  }
922	  return { state, effect: { stillActive: true } };
923	}
924	
925	/* ────────────────────────────────────────────────────────────────────── */
926	/* C17 Beam — two-click line placement                                      */
927	/* ────────────────────────────────────────────────────────────────────── */
928	
929	export type BeamState =
930	  | { phase: 'idle' }
931	  | { phase: 'first-point'; startMm: { xMm: number; yMm: number } };
932	
933	export type BeamEvent =
934	  | { kind: 'activate' }
935	  | { kind: 'deactivate' }
936	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
937	  | { kind: 'cancel' };
938	
939	export interface BeamEffect {
940	  commitBeam?: { startMm: { xMm: number; yMm: number }; endMm: { xMm: number; yMm: number } };
941	  stillActive: boolean;
942	}
943	
944	export function initialBeamState(): BeamState {
945	  return { phase: 'idle' };
946	}
947	
948	export function reduceBeam(
949	  state: BeamState,
950	  event: BeamEvent,
951	): { state: BeamState; effect: BeamEffect } {
952	  if (event.kind === 'deactivate') {
953	    return { state: initialBeamState(), effect: { stillActive: false } };
954	  }
955	  if (event.kind === 'activate' || event.kind === 'cancel') {
956	    return { state: initialBeamState(), effect: { stillActive: event.kind === 'activate' } };
957	  }
958	  if (event.kind === 'click') {
959	    if (state.phase === 'idle') {
960	      return {
961	        state: { phase: 'first-point', startMm: event.pointMm },
962	        effect: { stillActive: true },
963	      };
964	    }
965	    if (state.phase === 'first-point') {
966	      return {
967	        state: initialBeamState(),
968	        effect: {
969	          commitBeam: { startMm: state.startMm, endMm: event.pointMm },
970	          stillActive: true,
971	        },
972	      };
973	    }
974	  }
975	  return { state, effect: { stillActive: true } };
976	}
977	
978	/* ────────────────────────────────────────────────────────────────────── */
979	/* C18 Ceiling — sketch polygon (same grammar as Shaft)                     */
980	/* ────────────────────────────────────────────────────────────────────── */
981	
982	export type CeilingState =
983	  | { phase: 'idle' }
984	  | { phase: 'sketch'; verticesMm: Array<{ xMm: number; yMm: number }> };
985	
986	export type CeilingEvent =
987	  | { kind: 'activate' }
988	  | { kind: 'deactivate' }
989	  | { kind: 'click'; pointMm: { xMm: number; yMm: number } }
990	  | { kind: 'close-loop' }
991	  | { kind: 'cancel' };
992	
993	export interface CeilingEffect {
994	  commitCeiling?: { verticesMm: Array<{ xMm: number; yMm: number }> };
995	  stillActive: boolean;
996	}
997	
998	export function initialCeilingState(): CeilingState {
999	  return { phase: 'idle' } as CeilingState;
1000	}
1001	
1002	export function reduceCeiling(
1003	  state: CeilingState,
1004	  event: CeilingEvent,
1005	): { state: CeilingState; effect: CeilingEffect } {
1006	  if (event.kind === 'activate') {
1007	    return { state: { phase: 'idle' }, effect: { stillActive: true } };
1008	  }
1009	  if (event.kind === 'deactivate') {
1010	    return { state: { phase: 'idle' }, effect: { stillActive: false } };
1011	  }
1012	  if (event.kind === 'cancel') {
1013	    return { state: { phase: 'idle' }, effect: { stillActive: true } };
1014	  }
1015	  if (event.kind === 'click') {
1016	    const prev = state.phase === 'sketch' ? state.verticesMm : [];
1017	    return {
1018	      state: { phase: 'sketch', verticesMm: [...prev, event.pointMm] },
1019	      effect: { stillActive: true },
1020	    };
1021	  }
1022	  if (event.kind === 'close-loop') {
1023	    const verts = state.phase === 'sketch' ? state.verticesMm : [];
1024	    if (verts.length >= 3) {
1025	      return {
1026	        state: { phase: 'idle' },
1027	        effect: { commitCeiling: { verticesMm: verts }, stillActive: true },
1028	      };
1029	    }
1030	  }
1031	  return { state, effect: { stillActive: true } };
1032	}
