export interface RoofState {
  type: RoofType;
  slopeDeg: number;
  /** Per-edge slope override; key is edge index. */
  edgeSlopes: Record<number, boolean>;
  eaveOverhangMm: number;
}

export function initialRoofState(): RoofState {
  return {
    type: 'gable',
    slopeDeg: 35,
    edgeSlopes: {},
